// SetDryrunLastResult of the dataSource to the related item.
// Sets o.R.DryrunLastResult to related.
// Adds o to related.R.DryrunLastResultDataSources.
func (o *DataSource) SetDryrunLastResult(ctx context.Context, exec boil.ContextExecutor, insert bool, related *DryrunResult) error {
	var err error
	if insert {
		if err = related.Insert(ctx, exec, boil.Infer()); err != nil {
			return errors.Wrap(err, "failed to insert into foreign table")
		}
	}

	updateQuery := fmt.Sprintf(
		"UPDATE \"schema_ingest\".\"data_sources\" SET %s WHERE %s",
		strmangle.SetParamNames("\"", "\"", 1, []string{"dryrun_last_result_id"}),
		strmangle.WhereClause("\"", "\"", 2, dataSourcePrimaryKeyColumns),
	)
	values := []any{related.ID, o.ID}

	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, updateQuery)
		fmt.Fprintln(writer, values)
	}
	if _, err = exec.ExecContext(ctx, updateQuery, values...); err != nil {
		return errors.Wrap(err, "failed to update local table")
	}

	queries.Assign(&o.DryrunLastResultID, related.ID)
	if o.R == nil {
		o.R = &dataSourceR{
			DryrunLastResult: related,
		}
	} else {
		o.R.DryrunLastResult = related
	}

	if related.R == nil {
		related.R = &dryrunResultR{
			DryrunLastResultDataSources: DataSourceSlice{o},
		}
	} else {
		related.R.DryrunLastResultDataSources = append(related.R.DryrunLastResultDataSources, o)
	}

	return nil
}

// RemoveDryrunLastResult relationship.
// Sets o.R.DryrunLastResult to nil.
// Removes o from all passed in related items' relationships struct.
func (o *DataSource) RemoveDryrunLastResult(ctx context.Context, exec boil.ContextExecutor, related *DryrunResult) error {
	var err error

	queries.SetScanner(&o.DryrunLastResultID, nil)
	if _, err = o.Update(ctx, exec, boil.Whitelist("dryrun_last_result_id")); err != nil {
		return errors.Wrap(err, "failed to update local table")
	}

	if o.R != nil {
		o.R.DryrunLastResult = nil
	}
	if related == nil || related.R == nil {
		return nil
	}

	for i, ri := range related.R.DryrunLastResultDataSources {
		if queries.Equal(o.DryrunLastResultID, ri.DryrunLastResultID) {
			continue
		}

		ln := len(related.R.DryrunLastResultDataSources)
		if ln > 1 && i < ln-1 {
			related.R.DryrunLastResultDataSources[i] = related.R.DryrunLastResultDataSources[ln-1]
		}
		related.R.DryrunLastResultDataSources = related.R.DryrunLastResultDataSources[:ln-1]
		break
	}
	return nil
}

